import{_ as e,o as t,c as i,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Applications Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/roadmap.md","filePath":"10_core/40_service_apps/120_applications/roadmap.md"}'),o={name:"10_core/40_service_apps/120_applications/roadmap.md"};function n(l,a,s,d,p,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="applications-roadmap" tabindex="-1">Applications Roadmap <a class="header-anchor" href="#applications-roadmap" aria-label="Permalink to &quot;Applications Roadmap&quot;">​</a></h1><p>This page is the working roadmap for QiAccess and the related apps in the personal system.</p><p>It is intentionally portfolio-first.</p><p>The point is to make it obvious:</p><ul><li>what exists now</li><li>what is active</li><li>what is next</li><li>how each app relates back to QiAccess</li></ul><h2 id="portfolio-map" tabindex="-1">Portfolio Map <a class="header-anchor" href="#portfolio-map" aria-label="Permalink to &quot;Portfolio Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Project</th><th>Status</th><th>Primary role</th><th>Relationship to QiAccess</th><th>Notes</th></tr></thead><tbody><tr><td><a href="./portal">QiAccess Start Portal</a></td><td>Active foundation</td><td>Front door, launcher, knowledge access, system visibility</td><td>Core entry point</td><td>This is the main shell that should orient and route work across the system.</td></tr><tr><td><a href="./firefly">Firefly</a></td><td>Planned next app</td><td>Personal finance management and money review</td><td>Linked app launched from QiAccess</td><td>Firefly is the finance command layer for accounts, transactions, review, and reporting.</td></tr><tr><td><a href="./carelite">CareLite</a></td><td>Planned next app</td><td>Simple care tracker for Mom</td><td>Linked app launched from QiAccess</td><td>CareLite is the lightweight caregiver workflow for daily status, meds, notes, and check-ins.</td></tr><tr><td><a href="./../40_productivity/qiledger">QiLedger Blueprint</a></td><td>Prior blueprint</td><td>Finance architecture source material</td><td>Supporting reference</td><td>Keep as a finance draft that can feed Firefly instead of treating it as the final product name.</td></tr></tbody></table><h2 id="current-sequencing" tabindex="-1">Current Sequencing <a class="header-anchor" href="#current-sequencing" aria-label="Permalink to &quot;Current Sequencing&quot;">​</a></h2><h3 id="_1-foundation-now" tabindex="-1">1. Foundation now <a class="header-anchor" href="#_1-foundation-now" aria-label="Permalink to &quot;1. Foundation now&quot;">​</a></h3><ul><li>Keep QiAccess Start as the front door and organizing layer.</li><li>Use it to route into real apps instead of duplicating full workflows in the portal shell.</li></ul><h3 id="_2-next-build-targets" tabindex="-1">2. Next build targets <a class="header-anchor" href="#_2-next-build-targets" aria-label="Permalink to &quot;2. Next build targets&quot;">​</a></h3><ul><li>Firefly: finance management</li><li>CareLite: simple care tracking for Mom</li></ul><h3 id="_3-expansion-after-that" tabindex="-1">3. Expansion after that <a class="header-anchor" href="#_3-expansion-after-that" aria-label="Permalink to &quot;3. Expansion after that&quot;">​</a></h3><ul><li>Add more application pages here as new personal-system apps become real projects.</li><li>Keep one app page per product instead of hiding project plans in scattered notes.</li></ul><h2 id="roadmap-rules" tabindex="-1">Roadmap Rules <a class="header-anchor" href="#roadmap-rules" aria-label="Permalink to &quot;Roadmap Rules&quot;">​</a></h2><ol><li>QiAccess remains the portal. It should launch and explain apps, not absorb every workflow.</li><li>Each app should have one clear purpose, one primary user story, and one initial MVP.</li><li>If an older blueprint exists under another name, link it instead of duplicating the same planning material.</li><li>When a project moves from idea to implementation, update both this roadmap page and that app&#39;s dedicated page.</li></ol><h2 id="immediate-documentation-targets" tabindex="-1">Immediate Documentation Targets <a class="header-anchor" href="#immediate-documentation-targets" aria-label="Permalink to &quot;Immediate Documentation Targets&quot;">​</a></h2><ul><li>Firefly needs a dedicated finance blueprint with scope, workflows, and MVP boundaries.</li><li>CareLite needs a lightweight caregiver blueprint that stays simpler than a full clinical care platform.</li><li>QiAccess Start should continue documenting how these apps are reached from the front door.</li></ul>',18)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
